FUNCTION isInjective(f, A, B):
 // f: function represented as array/list
 // A: domain of size n
 // B: codomain
 FOR i FROM 0 TO n-1:
 FOR j FROM i+1 TO n-1:
 IF f[i] == f[j]:
 RETURN FALSE // Not injective
 RETURN TRUE // Injective

FUNCTION isSurjective(f, A, B):
 // f: function from A to B
 // Mark all elements in B as 'unvisited'
 visited[B] ← empty set
 FOR each x IN A:
 y ← f(x)
 visited ← visited ∪ {y}
 // Check if all elements in B are visited
 IF visited == B:
 RETURN TRUE // Surjective
 ELSE:
 RETURN FALSE
